import React from "react";
import { HashRouter as Router, Routes, Route, Link } from "react-router-dom";
import Home from "./pages/Home";
import About from "./pages/About";
import Projects from "./pages/Projects";

function App() {
  return (
    <Router>
      <div className="text-center p-4 bg-gray-100 shadow">
        <h1 className="text-2xl font-bold mb-4">Generative Architecture 🌐</h1>
        <nav className="space-x-4">
          <Link className="text-blue-500 hover:underline" to="/">Home</Link>
          <Link className="text-blue-500 hover:underline" to="/about">About</Link>
          <Link className="text-blue-500 hover:underline" to="/projects">Projects</Link>
        </nav>
      </div>

      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/projects" element={<Projects />} />
      </Routes>
    </Router>
  );
}

export default App;
